const item = $input.first();
const body = item?.json?.body || {};
const errors = [];

function text(name) {
  return String(body[name] ?? '').trim();
}
function optionalBoolean(name) {
  const raw = body[name];
  if (raw === undefined || raw === null || raw === '') return true;
  const v = String(raw).trim().toLowerCase();
  return ['true','false','1','0','yes','no','si','no','s','n','on','off'].includes(v);
}

if (!text('email_to')) {
  errors.push('email_to es obligatorio para llamadas webhook.');
}

for (const name of [
  'include_attachment',
  'include_detail',
  'include_summary',
  'include_operational_notes',
  'include_itop_button_footer',
  'send_email',
  'send_when_no_changes',
  'comparar_cargo',
  'comparar_departamento',
  'comparar_organizacion'
]) {
  if (!optionalBoolean(name)) errors.push(`${name} debe ser booleano compatible: true/false, 1/0, si/no.`);
}

const allowedModes = ['AUDITORIA'];
const mode = text('mode') || 'AUDITORIA';
if (!allowedModes.includes(mode.toUpperCase())) {
  errors.push(`mode no permitido: ${mode}. Valores permitidos: ${allowedModes.join(', ')}`);
}

const valid = errors.length === 0;

return [{
  json: {
    ...(item.json || {}),
    webhook_contract: {
      valid,
      status_code: valid ? 202 : 400,
      message: valid ? 'Workflow accepted' : errors.join(' '),
      errors,
    },
  },
  binary: item.binary,
}];

const item = $input.first();
const json = item?.json || {};

if (!json.webhook_contract?.valid) {
  return [];
}

const { webhook_contract, ...cleanJson } = json;
return [{ json: cleanJson, binary: item.binary }];

const base = $input.first()?.json || {};
const trigger = $('SetTrigger - Flujo').first()?.json || {};

function normalizeBoolean(value, fallback) {
  if (value === undefined || value === null || value === '') return fallback;
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value !== 0;
  const text = String(value).trim().toLowerCase();
  if (['true', '1', 'yes', 'y', 'si', 's', 'on', 'enabled'].includes(text)) return true;
  if (['false', '0', 'no', 'n', 'off', 'disabled'].includes(text)) return false;
  return fallback;
}

const flags = { ...(base.flags || {}) };
for (const key of [
  'include_attachment',
  'include_detail',
  'include_summary',
  'include_operational_notes',
  'include_itop_button_footer',
  'send_email',
  'send_when_no_changes'
]) {
  flags[key] = normalizeBoolean(trigger[key] ?? base[key], flags[key] ?? true);
}


// Para este reporte no aplica boton de acceso a iTop en el correo.
flags.include_itop_button_footer = false;

const config = {
  modo: String(trigger.mode || 'AUDITORIA').toUpperCase(),
  aplicarCambiosItop: false,
  llaveCruce: trigger.llave_cruce || 'email',
  nombreReporte: 'conciliacion_ad_itop',
  zonaHoraria: trigger.timezone || base.timezone || 'America/Santiago',
  criticidad: {
    crearEnItop: 'Media',
    inactivarEnItop: 'Alta',
    actualizarCargoRol: 'Media',
    excepciones: 'Alta'
  },
  ldap: {
    baseDn: trigger.ldap_base_dn,
    filter: trigger.ldap_filter,
    attributes: trigger.ldap_attributes,
    excludedEmailPatterns: ['svc_', 'adm_', 'test_', 'admin', 'notificaciones'],
    excludedOuContains: ['OU=Service Accounts', 'OU=Administradores', 'OU=Robots', 'OU=Aplicaciones']
  },
  itop: {
    url: String(trigger.itop_url || '').replace(/\/$/, '') + '/webservices/rest.php?version=1.3',
    baseUrl: trigger.itop_url,
    personClass: trigger.itop_person_class || 'Person',
    oqlPersonas: trigger.itop_oql_personas || "SELECT Person WHERE email != ''",
    fields: trigger.itop_output_fields || 'friendlyname,first_name,name,email,status,function,org_id,org_id_friendlyname'
  },
  comparacion: {
    compararCargo: normalizeBoolean(trigger.comparar_cargo, true),
    compararDepartamento: false,
    compararOrganizacion: false,
    normalizarTildes: true,
    ignorarMayusculas: true,
    crearHojaSinAccion: false
  },
  mail: {
    from: trigger.email_from,
    to: trigger.email_to,
    cc: trigger.email_cc || '',
    bcc: trigger.email_bcc || '',
    subjectPrefix: trigger.email_subject || 'Conciliacion semanal AD vs iTop',
    enviarSiempre: true,
    enviarAdjuntoSiNoHayCambios: true
  }
};

const errors = [];
function required(path, value) {
  if (value === undefined || value === null || String(value).trim() === '') errors.push(`Parametro obligatorio no informado: ${path}`);
}
required('ldap_base_dn', config.ldap.baseDn);
required('ldap_filter', config.ldap.filter);
required('ldap_attributes', config.ldap.attributes);
required('itop_url', trigger.itop_url);
required('email_from', config.mail.from);
required('email_to', config.mail.to);

if (config.aplicarCambiosItop !== false) {
  errors.push('Control de seguridad: aplicarCambiosItop debe permanecer en false para Fase 1.');
}

const setMixed = {
  ...base,
  ...trigger,
  flags,
  config,
  config_source: 'SetBase + SetTrigger + Config Reporte',
  config_validated: errors.length === 0,
  config_message: errors.length === 0 ? 'Parametros de configuracion validados' : errors.join(' | '),
};

for (const [key, value] of Object.entries(flags)) {
  setMixed[key] = value;
}

if (!setMixed.config_validated) {
  throw new Error(setMixed.config_message);
}

return [{ json: setMixed }];

const cfg = $('Config Reporte').first().json.config;

function clean(v) {
  if (v === undefined || v === null) return '';
  if (Array.isArray(v)) v = v[0] ?? '';
  return String(v).trim();
}
function emailNorm(v) { return clean(v).toLowerCase(); }
function containsAny(value, list) {
  const v = clean(value).toLowerCase();
  return (list || []).some(x => v.includes(String(x).toLowerCase()));
}

const users = [];
for (const item of $input.all()) {
  const j = item.json;
  const email = emailNorm(j.mail || j.email);
  const dn = clean(j.distinguishedName || j.dn);
  const login = clean(j.sAMAccountName || j.samaccountname);
  const excludedByPattern = containsAny(email, cfg.ldap.excludedEmailPatterns) || containsAny(login, cfg.ldap.excludedEmailPatterns);
  const excludedByOu = containsAny(dn, cfg.ldap.excludedOuContains);

  // Evita objetos hijos que pueden aparecer bajo usuarios, por ejemplo ExchangeActiveSyncDevices.
  // Esos registros no son cuentas de usuario y no deben generar excepciones ni filas con DN/OU.
  const dnLower = dn.toLowerCase();
  const objectClassText = clean(j.objectClass || j.objectclass).toLowerCase();
  const isExchangeMobileDevice = dnLower.includes('cn=exchangeactivesyncdevices') || dnLower.includes('cn=ipadÂ§') || dnLower.includes('cn=iphoneÂ§') || dnLower.includes('cn=androidÂ§');
  const isComputerLike = objectClassText.includes('computer') || objectClassText.includes('msExchActiveSyncDevice'.toLowerCase());

  if (isExchangeMobileDevice || isComputerLike) {
    continue;
  }

  users.push({
    source: 'AD',
    email,
    login,
    upn: clean(j.userPrincipalName),
    display_name: clean(j.displayName),
    employee_number: clean(j.employeeNumber || j.EmployeeNumber || j.employeeID),
    department: clean(j.department),
    office: clean(j.physicalDeliveryOfficeName || j.office || j.Office),
    title: clean(j.title || j.Title),
    first_name: clean(j.givenName),
    last_name: clean(j.sn),
    company: clean(j.company),
    dn,
    user_account_control: clean(j.userAccountControl),
    when_changed: clean(j.whenChanged),
    enabled: true,
    excluded: excludedByPattern || excludedByOu,
    exclusion_reason: excludedByPattern ? 'Cuenta excluida por patron tecnico' : (excludedByOu ? 'Cuenta excluida por OU tecnica' : '')
  });
}
return [{ json: { adUsers: users } }];

function clean(v) {
  if (v === undefined || v === null) return '';
  return String(v).trim();
}
function emailNorm(v) { return clean(v).toLowerCase(); }

function flattenInput(items) {
  const rows = [];
  for (const item of items) {
    const j = item.json || {};

    // Respuesta clÃ¡sica REST core/get: { objects: { Person::1: { fields: ... } } }
    if (j.objects && typeof j.objects === 'object') {
      for (const [key, value] of Object.entries(j.objects)) {
        rows.push({ key, ...(value || {}), fields: value?.fields || value || {} });
      }
      continue;
    }

    // Algunos nodos devuelven data.objects
    if (j.data?.objects && typeof j.data.objects === 'object') {
      for (const [key, value] of Object.entries(j.data.objects)) {
        rows.push({ key, ...(value || {}), fields: value?.fields || value || {} });
      }
      continue;
    }

    // Nodo nativo iTop: normalmente entrega un item por objeto, con campos planos o fields.
    if (Array.isArray(j)) {
      for (const row of j) rows.push(row);
      continue;
    }

    rows.push(j);
  }
  return rows;
}

function getField(obj, names, fallback = '') {
  for (const name of names) {
    if (obj && obj[name] !== undefined && obj[name] !== null && obj[name] !== '') return obj[name];
    if (obj?.fields && obj.fields[name] !== undefined && obj.fields[name] !== null && obj.fields[name] !== '') return obj.fields[name];
  }
  return fallback;
}

const rows = flattenInput($input.all());
const users = [];

for (const row of rows) {
  const fields = row.fields || row;
  users.push({
    source: 'iTop',
    key: clean(row.key || row.id || getField(fields, ['id', '_key', 'key'], '')),
    class: clean(row.class || row.finalclass || getField(fields, ['finalclass', 'class'], 'Person')) || 'Person',
    email: emailNorm(getField(fields, ['email'], '')),
    friendlyname: clean(getField(fields, ['friendlyname', 'friendly_name'], '')),
    first_name: clean(getField(fields, ['first_name', 'firstname'], '')),
    last_name: clean(getField(fields, ['name', 'last_name', 'lastname'], '')),
    status: clean(getField(fields, ['status', 'status_friendlyname'], '')),
    title: clean(getField(fields, ['function', 'function_friendlyname', 'title'], '')),
    department: clean(getField(fields, ['department', 'department_name', 'department_friendlyname'], '')),
    org_id: clean(getField(fields, ['org_id'], '')),
    org_name: clean(getField(fields, ['org_id_friendlyname', 'org_name', 'org_friendlyname'], ''))
  });
}

return [{ json: { itopUsers: users } }];

const cfg = $('Config Reporte').first().json.config;
const sys = { trigger_source: $('SetTrigger - Flujo').first()?.json?.body ? 'webhook' : 'manual/cron' };
const input = $input.first().json;
const adUsersRaw = input.adUsers || [];
const itopUsersRaw = input.itopUsers || [];

function clean(v) {
  if (v === undefined || v === null) return '';
  return String(v).trim();
}
function stripAccents(s) {
  return clean(s).normalize('NFD').replace(/[\u0300-\u036f]/g, '');
}
function normText(v) {
  let s = clean(v);
  if (cfg.comparacion?.normalizarTildes) s = stripAccents(s);
  if (cfg.comparacion?.ignorarMayusculas) s = s.toLowerCase();
  return s.replace(/\s+/g, ' ').trim();
}
function emailNorm(v) { return clean(v).toLowerCase(); }
function add(map, key, value) {
  if (!map.has(key)) map.set(key, []);
  map.get(key).push(value);
}

const adUsers = adUsersRaw.filter(u => !u.excluded);
const adExcluded = adUsersRaw.filter(u => u.excluded);
const itopUsers = itopUsersRaw;

const adByEmail = new Map();
const itopByEmail = new Map();
for (const u of adUsers) add(adByEmail, emailNorm(u.email), u);
for (const u of itopUsers) add(itopByEmail, emailNorm(u.email), u);

const resumen = {
  fecha_ejecucion: new Date().toISOString(),
  origen_ejecucion: sys.trigger_source || 'desconocido',
  modo: cfg.modo,
  aplica_cambios_itop: cfg.aplicarCambiosItop,
  total_ad_vigentes: adUsers.length,
  total_ad_excluidos: adExcluded.length,
  total_itop: itopUsers.length,
  coincidencias_email: 0,
  crear_en_itop: 0,
  inactivar_en_itop: 0,
  diferencias_datos: 0,
  excepciones: 0,
  sin_accion: 0
};

const crear = [];
const inactivar = [];
const diferencias = [];
const excepciones = [];
const sinAccion = [];

function pushException(origen, email, nombre, problema, impacto, accion, prioridad='Alta', source = {}) {
  const sourceObj = source || {};
  const fallbackEmail = clean(email)
    || clean(sourceObj.email)
    || clean(sourceObj.upn)
    || clean(sourceObj.userPrincipalName)
    || clean(sourceObj.UserPrincipalName)
    || clean(sourceObj.login)
    || clean(sourceObj.key)
    || `${origen}_SIN_CORREO`;
  const fallbackNombre = clean(nombre)
    || clean(sourceObj.display_name)
    || clean(sourceObj.displayName)
    || clean(sourceObj.friendlyname)
    || clean(sourceObj.first_name || sourceObj.last_name ? `${sourceObj.first_name || ''} ${sourceObj.last_name || ''}` : '')
    || clean(sourceObj.login)
    || clean(sourceObj.key)
    || `${origen} sin nombre informado`;

  excepciones.push({
    categoria: 'EXCEPCION',
    origen,
    email: fallbackEmail,
    email_ad: origen === 'AD' ? clean(sourceObj.email || email) : '',
    email_itop: origen === 'iTop' ? clean(sourceObj.email || email) : '',
    nombre: fallbackNombre,
    display_name_ad: clean(sourceObj.display_name || sourceObj.displayName),
    upn_ad: clean(sourceObj.upn || sourceObj.userPrincipalName || sourceObj.UserPrincipalName),
    login_ad: clean(sourceObj.login),
    dn_ad: clean(sourceObj.dn),
    friendlyname_itop: clean(sourceObj.friendlyname),
    key_itop: clean(sourceObj.key),
    departamento_ad: clean(sourceObj.department),
    oficina_area_ad: clean(sourceObj.office),
    cargo_puesto_ad: clean(sourceObj.title),
    cargo_itop: clean(sourceObj.title),
    problema,
    impacto,
    accion_recomendada: accion,
    prioridad
  });
}

for (const u of adExcluded) {
  pushException('AD', u.email, u.display_name, u.exclusion_reason || 'Cuenta excluida', 'No se considera en conciliacion operacional', 'Validar si corresponde excluir definitivamente', 'Baja', u);
}
for (const u of adUsers) {
  if (!u.email) pushException('AD', '', u.display_name, 'Usuario AD sin correo', 'No puede cruzarse por mail', 'Completar atributo mail en AD', 'Alta', u);
}
for (const u of itopUsers) {
  if (!u.email) pushException('iTop', '', u.friendlyname, 'Persona iTop sin correo', 'No puede cruzarse por mail', 'Completar correo en iTop', 'Alta', u);
}
for (const [email, arr] of adByEmail.entries()) {
  if (email && arr.length > 1) pushException('AD', email, arr.map(x => x.display_name || x.login || x.upn).filter(Boolean).join(' | '), 'Correo duplicado en AD', 'Llave de cruce no unica', 'Corregir duplicidad antes de accionar', 'Alta', { ...arr[0], email, display_name: arr.map(x => x.display_name || x.login || x.upn).filter(Boolean).join(' | ') });
}
for (const [email, arr] of itopByEmail.entries()) {
  if (email && arr.length > 1) pushException('iTop', email, arr.map(x => x.friendlyname || x.key).filter(Boolean).join(' | '), 'Correo duplicado en iTop', 'Llave de cruce no unica', 'Corregir duplicidad antes de accionar', 'Alta', { ...arr[0], email, friendlyname: arr.map(x => x.friendlyname || x.key).filter(Boolean).join(' | ') });
}

const allEmails = new Set([...adByEmail.keys(), ...itopByEmail.keys()].filter(Boolean));

for (const email of allEmails) {
  const adList = adByEmail.get(email) || [];
  const itopList = itopByEmail.get(email) || [];

  if (adList.length !== 1 || itopList.length > 1) continue;

  if (itopList.length === 0) {
    const ad = adList[0];
    crear.push({
      categoria: 'CREAR_EN_ITOP',
      accion_propuesta: 'Crear persona en iTop',
      criticidad: cfg.criticidad.crearEnItop,
      email,
      email_ad: ad.email || ad.upn || email,
      email_itop: '',
      nombre_ad: ad.first_name,
      apellido_ad: ad.last_name,
      display_name_ad: ad.display_name,
      login_ad: ad.login,
      upn_ad: ad.upn,
      numero_empleado_ad: ad.employee_number,
      cargo_puesto_ad: ad.title,
      cargo_ad: ad.title,
      departamento_ad: ad.department,
      oficina_area_ad: ad.office,
      empresa_ad: ad.company,
      ou_ad: ad.dn,
      motivo: 'Existe vigente en AD y no existe en iTop',
      requiere_revision: 'Si'
    });
    continue;
  }

  const ad = adList[0];
  const itop = itopList[0];
  resumen.coincidencias_email++;

  const changed = [];
  if (cfg.comparacion.compararCargo && normText(ad.title) !== normText(itop.title)) changed.push('cargo/rol');
  // Fase actual: solo se evalua diferencia de cargo/rol. Departamento y organizacion quedan fuera del analisis.


  if (changed.length > 0) {
    diferencias.push({
      categoria: 'DIFERENCIA_DATOS',
      accion_propuesta: 'Actualizar datos en iTop',
      criticidad: cfg.criticidad.actualizarCargoRol,
      email,
      email_ad: ad.email || ad.upn || email,
      email_itop: itop.email || email,
      upn_ad: ad.upn,
      login_ad: ad.login,
      nombre_ad: ad.display_name,
      nombre_itop: itop.friendlyname,
      numero_empleado_ad: ad.employee_number,
      cargo_puesto_ad: ad.title,
      cargo_ad: ad.title,
      cargo_itop: itop.title,
      departamento_ad: ad.department,
      oficina_area_ad: ad.office,
      departamento_itop: itop.department,
      empresa_ad: ad.company,
      organizacion_itop: itop.org_name,
      campos_con_diferencia: changed.join(', '),
      motivo: 'Datos distintos entre AD e iTop',
      requiere_revision: 'Si'
    });
  } else {
    sinAccion.push({
      categoria: 'SINCRONIZADO',
      email,
      email_ad: ad.email || ad.upn || email,
      email_itop: itop.email || email,
      upn_ad: ad.upn,
      login_ad: ad.login,
      nombre: ad.display_name || itop.friendlyname,
      nombre_ad: ad.display_name,
      nombre_itop: itop.friendlyname,
      numero_empleado_ad: ad.employee_number,
      cargo_puesto_ad: ad.title,
      cargo: ad.title || itop.title,
      cargo_ad: ad.title,
      cargo_itop: itop.title,
      departamento: ad.department || itop.department,
      departamento_ad: ad.department,
      oficina_area_ad: ad.office,
      departamento_itop: itop.department,
      estado: 'OK',
      motivo: 'Registro sincronizado: correo y cargo/rol coinciden segun reglas configuradas'
    });
  }
}

for (const [email, itopList] of itopByEmail.entries()) {
  if (!email) continue;
  const adList = adByEmail.get(email) || [];
  if (itopList.length !== 1 || adList.length > 0) continue;

  const itop = itopList[0];
  inactivar.push({
    categoria: 'INACTIVAR_EN_ITOP',
    accion_propuesta: 'Candidato a inactivar en iTop',
    criticidad: cfg.criticidad.inactivarEnItop,
    email,
    email_itop: itop.email || email,
    email_ad: '',
    nombre_itop: itop.friendlyname,
    estado_itop: itop.status,
    cargo_itop: itop.title,
    organizacion_itop: itop.org_name,
    existe_en_ad: 'No',
    estado_ad: 'No encontrado como vigente',
    motivo: 'Existe activo o registrado en iTop, pero no aparece vigente en AD',
    bloqueo_operativo: 'Pendiente de validar',
    motivo_bloqueo: 'Validar activos asignados, tickets abiertos y actas antes de inactivar',
    requiere_revision: 'Si'
  });
}

resumen.crear_en_itop = crear.length;
resumen.inactivar_en_itop = inactivar.length;
resumen.diferencias_datos = diferencias.length;
resumen.excepciones = excepciones.length;
resumen.sin_accion = sinAccion.length;

const totalCambios = crear.length + inactivar.length + diferencias.length + excepciones.length;

return [{
  json: {
    config: cfg,
    sys,
    resumen,
    totalCambios,
    hayCambios: totalCambios > 0,
    hojas: {
      '00_Resumen': [
        { indicador: 'Fecha ejecucion', valor: resumen.fecha_ejecucion, comentario: 'Ejecucion semanal o bajo demanda' },
        { indicador: 'Origen ejecucion', valor: resumen.origen_ejecucion, comentario: 'manual, cron o webhook' },
        { indicador: 'Modo', valor: resumen.modo, comentario: 'No aplica cambios automaticos' },
        { indicador: 'Usuarios AD vigentes', valor: resumen.total_ad_vigentes, comentario: 'Fuente LDAP' },
        { indicador: 'Usuarios AD excluidos', valor: resumen.total_ad_excluidos, comentario: 'Cuentas tecnicas u OU excluidas' },
        { indicador: 'Personas iTop procesadas', valor: resumen.total_itop, comentario: 'Fuente REST/OQL' },
        { indicador: 'Coincidencias por email', valor: resumen.coincidencias_email, comentario: 'Match principal' },
        { indicador: 'Candidatos a crear', valor: resumen.crear_en_itop, comentario: 'AD si / iTop no' },
        { indicador: 'Candidatos a inactivar', valor: resumen.inactivar_en_itop, comentario: 'iTop si / AD no' },
        { indicador: 'Diferencias de datos', valor: resumen.diferencias_datos, comentario: 'Cargo/rol' },
        { indicador: 'Excepciones', valor: resumen.excepciones, comentario: 'Requieren revision' },
        { indicador: 'Sincronizados / Estado correcto', valor: resumen.sin_accion, comentario: 'Correo y cargo/rol coinciden segun reglas activas' }
      ],
      '01_Crear_en_iTop': crear,
      '02_Inactivar_en_iTop': inactivar,
      '03_Diferencias_Datos': diferencias,
      '04_Sin_Accion': sinAccion,
      '05_Excepciones': excepciones
    }
  }
}];

const cfg = $json.config || {};
const trigger = $('SetTrigger - Flujo').first()?.json || {};
const flags = $('Config Reporte').first()?.json?.flags || {};
const resumen = $json.resumen || {};
const hojasOriginales = $json.hojas || {};
const hayCambios = $json.hayCambios === true;
const totalCambios = Number($json.totalCambios || 0);
const timezone = cfg.zonaHoraria || cfg.timezone || 'America/Santiago';

function clean(value) {
  if (value === undefined || value === null) return '';
  return String(value).trim();
}

function normalizeBoolean(value, fallback = true) {
  if (value === undefined || value === null || value === '') return fallback;
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value !== 0;
  const text = String(value).trim().toLowerCase();
  if (['true', '1', 'yes', 'y', 'si', 's', 'on', 'enabled'].includes(text)) return true;
  if (['false', '0', 'no', 'n', 'off', 'disabled'].includes(text)) return false;
  return fallback;
}

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function escXml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&apos;')
    .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, '');
}

function colName(n) {
  let s = '';
  while (n > 0) {
    const m = (n - 1) % 26;
    s = String.fromCharCode(65 + m) + s;
    n = Math.floor((n - m) / 26);
  }
  return s;
}

function safeSheetName(name, index, used) {
  let safe = clean(name || `Hoja_${index + 1}`)
    .replace(/[\\/?*\[\]:]/g, '_')
    .replace(/^'+|'+$/g, '')
    .substring(0, 31);
  if (!safe) safe = `Hoja_${index + 1}`;
  let candidate = safe;
  let counter = 2;
  while (used.has(candidate.toLowerCase())) {
    const suffix = `_${counter++}`;
    candidate = safe.substring(0, 31 - suffix.length) + suffix;
  }
  used.add(candidate.toLowerCase());
  return candidate;
}

function rowsForSheet(rows) {
  const normalizedRows = Array.isArray(rows) ? rows : [];
  const cols = [];
  for (const row of normalizedRows) {
    for (const key of Object.keys(row || {})) {
      if (!cols.includes(key)) cols.push(key);
    }
  }
  if (!cols.length) cols.push('sin_datos');
  if (!normalizedRows.length) return { cols, rows: [{ sin_datos: 'Sin registros para esta hoja' }] };
  return { cols, rows: normalizedRows };
}

function sheetXml(rows) {
  const { cols, rows: dataRows } = rowsForSheet(rows);
  const allRows = [Object.fromEntries(cols.map(c => [c, c])), ...dataRows];
  const rowXml = allRows.map((row, rowIndex) => {
    const cells = cols.map((col, colIndex) => {
      const ref = `${colName(colIndex + 1)}${rowIndex + 1}`;
      const value = escXml(row?.[col] ?? '');
      return `<c r="${ref}" t="inlineStr"><is><t>${value}</t></is></c>`;
    }).join('');
    return `<row r="${rowIndex + 1}">${cells}</row>`;
  }).join('');
  return `<?xml version="1.0" encoding="UTF-8" standalone="yes"?><worksheet xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main"><sheetData>${rowXml}</sheetData></worksheet>`;
}

function crc32(buffer) {
  const table = crc32.table || (crc32.table = (() => {
    const t = [];
    for (let n = 0; n < 256; n++) {
      let c = n;
      for (let k = 0; k < 8; k++) c = (c & 1) ? (0xEDB88320 ^ (c >>> 1)) : (c >>> 1);
      t[n] = c >>> 0;
    }
    return t;
  })());
  let crc = 0 ^ (-1);
  for (let i = 0; i < buffer.length; i++) crc = (crc >>> 8) ^ table[(crc ^ buffer[i]) & 0xFF];
  return (crc ^ (-1)) >>> 0;
}

function dosDateTime(date = new Date()) {
  return {
    time: (date.getHours() << 11) | (date.getMinutes() << 5) | Math.floor(date.getSeconds() / 2),
    date: ((date.getFullYear() - 1980) << 9) | ((date.getMonth() + 1) << 5) | date.getDate(),
  };
}

function zipStore(files) {
  const localParts = [];
  const centralParts = [];
  let offset = 0;
  const dt = dosDateTime();

  for (const file of files) {
    const name = Buffer.from(file.name, 'utf8');
    const data = Buffer.from(file.data, 'utf8');
    const crc = crc32(data);
    const local = Buffer.alloc(30);
    local.writeUInt32LE(0x04034b50, 0);
    local.writeUInt16LE(20, 4);
    local.writeUInt16LE(0, 6);
    local.writeUInt16LE(0, 8);
    local.writeUInt16LE(dt.time, 10);
    local.writeUInt16LE(dt.date, 12);
    local.writeUInt32LE(crc, 14);
    local.writeUInt32LE(data.length, 18);
    local.writeUInt32LE(data.length, 22);
    local.writeUInt16LE(name.length, 26);
    local.writeUInt16LE(0, 28);
    localParts.push(local, name, data);

    const central = Buffer.alloc(46);
    central.writeUInt32LE(0x02014b50, 0);
    central.writeUInt16LE(20, 4);
    central.writeUInt16LE(20, 6);
    central.writeUInt16LE(0, 8);
    central.writeUInt16LE(0, 10);
    central.writeUInt16LE(dt.time, 12);
    central.writeUInt16LE(dt.date, 14);
    central.writeUInt32LE(crc, 16);
    central.writeUInt32LE(data.length, 20);
    central.writeUInt32LE(data.length, 24);
    central.writeUInt16LE(name.length, 28);
    central.writeUInt16LE(0, 30);
    central.writeUInt16LE(0, 32);
    central.writeUInt16LE(0, 34);
    central.writeUInt16LE(0, 36);
    central.writeUInt32LE(0, 38);
    central.writeUInt32LE(offset, 42);
    centralParts.push(central, name);
    offset += local.length + name.length + data.length;
  }

  const centralSize = centralParts.reduce((sum, part) => sum + part.length, 0);
  const end = Buffer.alloc(22);
  end.writeUInt32LE(0x06054b50, 0);
  end.writeUInt16LE(0, 4);
  end.writeUInt16LE(0, 6);
  end.writeUInt16LE(files.length, 8);
  end.writeUInt16LE(files.length, 10);
  end.writeUInt32LE(centralSize, 12);
  end.writeUInt32LE(offset, 16);
  end.writeUInt16LE(0, 20);
  return Buffer.concat([...localParts, ...centralParts, end]);
}

function buildWorkbook(sheets) {
  const entries = Object.entries(sheets || {});
  if (!entries.length) entries.push(['00_Resumen', [{ indicador: 'Estado', valor: 'Sin datos', comentario: 'No se recibieron hojas desde la conciliacion' }]]);

  const usedNames = new Set();
  const prepared = entries.map(([name, rows], index) => ({
    name: safeSheetName(name, index, usedNames),
    rows: Array.isArray(rows) ? rows : [],
  }));

  const files = [];
  files.push({ name: '[Content_Types].xml', data: `<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Override PartName="/xl/workbook.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet.main+xml"/>${prepared.map((_, i) => `<Override PartName="/xl/worksheets/sheet${i + 1}.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.worksheet+xml"/>`).join('')}</Types>` });
  files.push({ name: '_rels/.rels', data: `<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="xl/workbook.xml"/></Relationships>` });
  files.push({ name: 'xl/workbook.xml', data: `<?xml version="1.0" encoding="UTF-8" standalone="yes"?><workbook xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships"><sheets>${prepared.map((sheet, i) => `<sheet name="${escXml(sheet.name)}" sheetId="${i + 1}" r:id="rId${i + 1}"/>`).join('')}</sheets></workbook>` });
  files.push({ name: 'xl/_rels/workbook.xml.rels', data: `<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">${prepared.map((_, i) => `<Relationship Id="rId${i + 1}" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/worksheet" Target="worksheets/sheet${i + 1}.xml"/>`).join('')}</Relationships>` });
  prepared.forEach((sheet, i) => files.push({ name: `xl/worksheets/sheet${i + 1}.xml`, data: sheetXml(sheet.rows) }));
  return { buffer: zipStore(files), sheetNames: prepared.map(s => s.name) };
}

