function csvEscape(value) {
  const text = String(value ?? '').replace(/"/g, '""');
  return `"${text}"`;
}

function isEmail(value) {
  const text = clean(value).toLowerCase();
  if (!text) return '';
  // Evita que DN/OU/rutas LDAP u otros identificadores terminen en columnas de correo.
  if (/[=,]/.test(text) || /(^|\b)(ou|cn|dc)=/i.test(text)) return '';
  return /^[^\s@<>;,"']+@[^\s@<>;,"']+\.[^\s@<>;,"']+$/.test(text) ? text : '';
}

function firstValue(row, names, fallback = '') {
  for (const name of names) {
    const value = row?.[name];
    if (value !== undefined && value !== null && String(value).trim() !== '') return value;
  }
  return fallback;
}

function firstEmail(row, names, fallback = '') {
  for (const name of names) {
    const email = isEmail(row?.[name]);
    if (email) return email;
  }
  return isEmail(fallback);
}

function hasDnOrOu(value) {
  const text = clean(value);
  if (!text) return false;
  return /(^|[,\s])(CN|OU|DC)=/i.test(text) || /distinguishedName/i.test(text);
}

function safeDisplayValue(value) {
  const text = clean(value);
  if (!text) return '';
  return hasDnOrOu(text) ? '' : text;
}

function firstSafeValue(row, names, fallback = '') {
  for (const name of names) {
    const value = safeDisplayValue(row?.[name]);
    if (value) return value;
  }
  return safeDisplayValue(fallback);
}

function isMultiUserRow(row) {
  if (!row || typeof row !== 'object') return false;

  // Multi User solo aplica si la propia conciliacion clasifico la fila como duplicidad real.
  // No se infiere por separadores, nombres compuestos ni por columnas auxiliares.
  const categoria = clean(row.categoria || row.estado).toUpperCase();
  const problema = clean(row.problema || row.motivo || row.observacion)
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase();
  const impacto = clean(row.impacto)
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase();

  if (categoria !== 'EXCEPCION') return false;
  if (/correo\s+duplicado\s+en\s+ad/.test(problema)) return true;
  if (/correo\s+duplicado\s+en\s+itop/.test(problema)) return true;
  if (/llave\s+de\s+cruce\s+no\s+unica/.test(impacto)) return true;
  return false;
}

function normalizeDetailRow(row, forcedEstado) {
  const estado = firstValue(row, ['categoria', 'estado'], forcedEstado);
  const origen = firstValue(row, ['origen'], '');

  let emailItop = firstEmail(row, ['email_itop', 'correo_itop']);
  let emailAd = firstEmail(row, ['email_ad', 'correo_ad', 'upn_ad', 'userPrincipalName', 'UserPrincipalName']);
  const emailComun = firstEmail(row, ['email', 'correo']);

  // El campo historico "email" solo se copia si tiene formato real de correo.
  if (!emailItop && ['INACTIVAR_EN_ITOP', 'DIFERENCIA_DATOS', 'SIN_ACCION', 'SINCRONIZADO'].includes(String(estado))) emailItop = emailComun;
  if (!emailAd && ['CREAR_EN_ITOP', 'DIFERENCIA_DATOS', 'SIN_ACCION', 'SINCRONIZADO'].includes(String(estado))) emailAd = emailComun;
  if (!emailItop && origen === 'iTop') emailItop = emailComun;
  if (!emailAd && origen === 'AD') emailAd = emailComun;

  const multiUser = isMultiUserRow(row);
  let usuario = multiUser ? 'Multi User' : firstSafeValue(row, [
    'display_name_ad', 'nombre_ad', 'nombre', 'nombre_itop', 'friendlyname_itop', 'friendlyname',
    'usuario', 'login_ad', 'login', 'key_itop', 'key'
  ], '');

  const puestoAd = firstSafeValue(row, ['cargo_puesto_ad', 'puesto_ad', 'title', 'Title', 'cargo_ad', 'cargo'], '');
  const puestoItop = firstSafeValue(row, ['cargo_itop', 'puesto_itop', 'function_itop'], '');
  const observacion = firstValue(row, ['motivo', 'observacion', 'problema', 'accion_recomendada'], '');
  const diff = firstValue(row, ['campos_con_diferencia'], '');
  const accion = firstValue(row, ['accion_propuesta'], '');
  const requiereRevision = firstValue(row, ['requiere_revision'], '');
  const impacto = firstValue(row, ['impacto'], '');
  const loginAd = firstSafeValue(row, ['login_ad', 'login'], '');
  const keyItop = firstSafeValue(row, ['key_itop', 'key'], '');

  if (!usuario) usuario = loginAd || keyItop || emailAd || emailItop || `${origen || forcedEstado || 'Registro'} sin nombre informado`;

  const partes = [];
  if (observacion) partes.push(String(observacion));
  if (multiUser) {
    const emailDuplicado = emailAd || emailItop || emailComun || 'correo no determinado';
    partes.push(`Mas de un usuario comparte el correo ${emailDuplicado}; se consolida como Multi User para revision operacional.`);
  }
  if (impacto) partes.push(`Impacto: ${impacto}`);
  if (diff) partes.push(`Campos con diferencia: ${diff}`);
  if (accion) partes.push(`Accion propuesta: ${accion}`);
  if (requiereRevision) partes.push(`Requiere revision: ${requiereRevision}`);
  if (origen) partes.push(`Origen: ${origen}`);
  if (loginAd && usuario !== 'Multi User' && loginAd !== usuario) partes.push(`Login AD: ${loginAd}`);
  if (keyItop && usuario !== 'Multi User' && keyItop !== usuario) partes.push(`Key iTop: ${keyItop}`);
  if ((!emailAd && origen === 'AD') || (!emailItop && origen === 'iTop')) {
    partes.push('Registro sin correo valido en origen; no se informa OU/DN en columnas de correo.');
  }

  return {
    'Email iTop': emailItop,
    'Email AD': emailAd,
    'Estado': estado || forcedEstado,
    'Usuario': usuario,
    'Puesto AD': puestoAd,
    'Puesto iTop': puestoItop,
    'Observacion': partes.join(' | ').replace(/(?:CN|OU|DC)=[^|]+(?:\|\s*)?/gi, '').replace(/\s{2,}/g, ' ').trim(),
  };
}

function normalizeEstadoLabel(value) {
  const estado = clean(value).toUpperCase();
  if (estado === 'SIN_ACCION' || estado === 'OK') return 'SINCRONIZADO';
  return estado || 'SIN_REGISTROS';
}

function humanEstadoLabel(value) {
  const estado = normalizeEstadoLabel(value);
  const labels = {
    'CREAR_EN_ITOP': 'Crear en iTop',
    'INACTIVAR_EN_ITOP': 'Desactivar en iTop',
    'DIFERENCIA_DATOS': 'Analizar diferencias',
    'EXCEPCION': 'Datos en excepciÃ³n',
    'SINCRONIZADO': 'Sincronizados',
    'SIN_REGISTROS': 'Sin registros',
  };
  return labels[estado] || estado;
}

function estadoOrder(estado) {
  const e = normalizeEstadoLabel(estado);
  const order = {
    'CREAR_EN_ITOP': 10,
    'INACTIVAR_EN_ITOP': 20,
    'DIFERENCIA_DATOS': 30,
    'EXCEPCION': 40,
    'SINCRONIZADO': 90,
    'SIN_REGISTROS': 99,
  };
  return order[e] ?? 80;
}

function buildDetalleRows(sheets) {
  const source = sheets || {};
  const buckets = [
    ['CREAR_EN_ITOP', source.crear || source['01_Crear_en_iTop'] || []],
    ['INACTIVAR_EN_ITOP', source.inactivar || source['02_Inactivar_en_iTop'] || []],
    ['DIFERENCIA_DATOS', source.diferencias || source['03_Diferencias_Datos'] || []],
    ['EXCEPCION', source.excepciones || source['05_Excepciones'] || []],
    // Los sincronizados se dejan al final para priorizar diferencias y excepciones.
    ['SINCRONIZADO', source.sinAccion || source.sin_accion || source['04_Sin_Accion'] || []],
  ];

  const rows = [];
  for (const [estado, rowsRaw] of buckets) {
    for (const row of (Array.isArray(rowsRaw) ? rowsRaw : [])) {
      const normalized = normalizeDetailRow(row || {}, estado);
      normalized.Estado = normalizeEstadoLabel(normalized.Estado || estado);
      rows.push(normalized);
    }
  }

  const outputRows = rows.length ? rows : [{
    'Email iTop': '',
    'Email AD': '',
    'Estado': 'SIN_REGISTROS',
    'Usuario': '',
    'Puesto AD': '',
    'Puesto iTop': '',
    'Observacion': 'Sin registros para exportar en esta ejecucion',
  }];

  return outputRows.sort((a, b) => {
    const diff = estadoOrder(a.Estado) - estadoOrder(b.Estado);
    if (diff !== 0) return diff;
    return String(a.Usuario || a['Email AD'] || a['Email iTop'] || '').localeCompare(String(b.Usuario || b['Email AD'] || b['Email iTop'] || ''), 'es');
  });
}

function buildDetalleTableHtml(rows) {
  // La columna Estado se omite solo en la tabla HTML del correo, porque ya se informa en la agrupacion.
  // Se mantiene en el CSV para trazabilidad y posterior analisis.
  const headers = ['Email iTop', 'Email AD', 'Usuario', 'Puesto AD', 'Puesto iTop', 'Observacion'];
  const list = Array.isArray(rows) ? rows : [];
  const countsByEstado = list.reduce((acc, row) => {
    const estado = normalizeEstadoLabel(row?.Estado);
    acc[estado] = (acc[estado] || 0) + 1;
    return acc;
  }, {});

  let currentEstado = null;
  const body = list.map(row => {
    const estado = normalizeEstadoLabel(row?.Estado);
    const estadoHumano = humanEstadoLabel(estado);
    const rowForMail = { ...row, Estado: estadoHumano };
    const groupHeader = estado !== currentEstado
      ? (() => {
          currentEstado = estado;
          const count = countsByEstado[estado] || 0;
          return `<tr><td colspan="${headers.length}" style="padding:8px 10px; background-color:#eef2f7; border-top:1px solid #cbd5e1; border-bottom:1px solid #cbd5e1; font-size:11px; line-height:15px; color:#0f172a; font-weight:bold;">Estado: ${escapeHtml(estadoHumano)} (${escapeHtml(count)})</td></tr>`;
        })()
      : '';
    const dataRow = `<tr>
      ${headers.map(header => `<td style="padding:7px 8px; border-bottom:1px solid #e5e7eb; font-size:11px; line-height:16px; color:#334155; vertical-align:top;">${escapeHtml(rowForMail?.[header] ?? '')}</td>`).join('')}
    </tr>`;
    return groupHeader + dataRow;
  }).join('');

  return `<div style="margin-top:14px;">
    <div style="font-size:14px; line-height:20px; font-weight:bold; color:#0f172a; margin-bottom:6px;">Tabla de datos</div>
    <div style="font-size:12px; line-height:18px; color:#64748b; margin-bottom:8px;">Registros agrupados por estado. Los sincronizados se muestran al final para facilitar el anÃ¡lisis de diferencias.</div>
    <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="border-collapse:collapse; border:1px solid #dbe3ec;">
      <thead><tr style="background-color:#f8fafc;">
        ${headers.map(header => `<th align="left" style="padding:8px; font-size:10px; line-height:14px; color:#334155; border-bottom:1px solid #dbe3ec; text-transform:uppercase;">${escapeHtml(header)}</th>`).join('')}
      </tr></thead>
      <tbody>${body}</tbody>
    </table>
  </div>`;
}

function buildCsv(sheets) {
  const outputRows = buildDetalleRows(sheets);
  const headers = ['Email iTop', 'Email AD', 'Estado', 'Usuario', 'Puesto AD', 'Puesto iTop', 'Observacion'];

  const lines = [headers.map(csvEscape).join(';')];
  for (const row of outputRows) {
    lines.push(headers.map(key => csvEscape(row[key] ?? '')).join(';'));
  }

  return {
    content: '\uFEFF' + lines.join('\r\n'),
    sheetNames: ['Detalle_Conciliacion'],
    rowCount: outputRows.length,
    rows: outputRows,
    tableHtml: buildDetalleTableHtml(outputRows),
  };
}

const csv = buildCsv(hojasOriginales);
