function getNodeJson(name) {
  try { return $(name).first()?.json || {}; } catch (error) { return {}; }
}

function normalizeBoolean(value, fallback = true) {
  if (value === undefined || value === null || value === '') return fallback;
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value !== 0;
  const text = String(value).trim().toLowerCase();
  if (['true', '1', 'yes', 'y', 'si', 's', 'on', 'enabled'].includes(text)) return true;
  if (['false', '0', 'no', 'n', 'off', 'disabled'].includes(text)) return false;
  return fallback;
}

function flagEnabled(data, name, fallback = true) {
  const trigger = getNodeJson('SetTrigger - Flujo');
  const mixed = getNodeJson('SetMixed - Configuracion efectiva');
  const value = trigger[name] ?? trigger.flags?.[name] ?? data[name] ?? data.flags?.[name] ?? mixed[name] ?? mixed.flags?.[name];
  return normalizeBoolean(value, fallback);
}

function notesList(value) {
  const lines = String(value ?? '')
    .split(/\r?\n|\. /)
    .map(v => v.trim().replace(/\.$/, ''))
    .filter(Boolean);
  if (!lines.length) return '<div style="font-size:13px; line-height:20px; color:#64748b;">Sin observaciones adicionales.</div>';
  return '<ul style="margin:0; padding-left:18px; color:#374151; font-size:13px; line-height:20px;">' +
    lines.map(line => '<li>' + escapeHtml(line) + '.</li>').join('') +
    '</ul>';
}

function statCard(data, stat) {
  const value = data[stat.value] ?? data[stat.fallbackValue] ?? '-';
  return '<td class="summary-card" width="33.33%" valign="top"><table role="presentation" width="100%" style="border:1px solid ' + stat.border + '; background-color:' + stat.background + ';"><tr><td style="padding:12px;"><div style="font-size:11px; color:' + stat.labelColor + '; font-weight:bold;">' + escapeHtml(stat.label) + '</div><div style="font-size:24px; color:' + stat.valueColor + '; font-weight:bold;">' + escapeHtml(value) + '</div></td></tr></table></td>';
}

function statRows(data, stats) {
  const rows = [];
  for (let i = 0; i < stats.length; i += 3) {
    const cells = stats.slice(i, i + 3).map(stat => statCard(data, stat));
    while (cells.length < 3) cells.push('<td class="summary-card" width="33.33%" valign="top">&nbsp;</td>');
    rows.push('<tr>' + cells.join('') + '</tr>');
  }
  return rows.join('\n');
}

function simpleTable(title, rows, headers, emptyText) {
  if (!rows) return '';
  const headerHtml = headers.map(h => '<th align="left" style="padding:8px; font-size:11px; color:#475569;">' + escapeHtml(h) + '</th>').join('');
  const body = rows || '<tr><td colspan="' + headers.length + '" style="padding:14px; font-size:12px; color:#64748b;">' + escapeHtml(emptyText || 'Sin registros.') + '</td></tr>';
  return '<div style="font-size:14px; font-weight:bold; color:#1e293b; margin:18px 0 8px 0;">' + escapeHtml(title) + '</div><table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="border-collapse:collapse; border:1px solid #dbe3ec;"><thead><tr style="background:#f8fafc;">' + headerHtml + '</tr></thead><tbody>' + body + '</tbody></table>';
}

function tableContent(data) {
  const blocks = [];
  for (const key of ['detail_blocks', 'grouped_section', 'detail_section', 'detail_table_html']) {
    if (data[key]) blocks.push(data[key]);
  }
  if (data.class_asset_blocks) blocks.push(data.class_asset_blocks);
  if (data.status_asset_blocks) blocks.push(data.status_asset_blocks);
  if (data.review_asset_blocks) blocks.push(data.review_asset_blocks);
  if (data.ticket_sections) blocks.push(data.ticket_sections);
  if (data.older_section) blocks.push(data.older_section);
  if (data.recent_section) blocks.push(data.recent_section);
  if (data.ticket_rows_html) blocks.push(simpleTable('Tickets abiertos', data.ticket_rows_html, ['Criticidad','Referencia','Tipo','Titulo','Solicitante','Estado','Creacion','Ultimo update','Antiguedad','SLA'], 'Sin tickets.'));
  if (data.movement_rows) blocks.push(simpleTable('Movimientos recientes', data.movement_rows, ['Fecha','Movimiento','Activo','Clase','Origen','Destino'], 'Sin movimientos.'));
  if (data.class_summary_rows) blocks.push(simpleTable('Resumen por clase', data.class_summary_rows, ['Clase','Total','Dato 1','Observacion'], 'Sin resumen por clase.'));
  if (data.warehouse_summary_rows) blocks.push(simpleTable('Resumen por bodega/localidad', data.warehouse_summary_rows, ['Bodega/localidad','Total','Clases','Observacion'], 'Sin resumen por bodega.'));
  if (data.status_summary_rows) blocks.push(simpleTable('Resumen por estado', data.status_summary_rows, ['Estado','Total','Dato 1','Observacion'], 'Sin resumen por estado.'));
  if (data.location_summary_rows) blocks.push(simpleTable('Resumen por localidad', data.location_summary_rows, ['Localidad','Total','Dato 1','Observacion'], 'Sin resumen por localidad.'));
  if (data.class_status_rows) blocks.push(simpleTable('Clase por estado', data.class_status_rows, ['Clase','Productivo','Inventario','No operativo'], 'Sin matriz de estados.'));
  if (data.location_matrix_rows) {
    const header = data.location_matrix_header_cells || '<th align="left" style="padding:8px; font-size:11px; color:#475569;">Bodega/localidad</th>';
    blocks.push('<div style="font-size:14px; font-weight:bold; color:#1e293b; margin:18px 0 8px 0;">Matriz por bodega/localidad</div><table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="border-collapse:collapse; border:1px solid #dbe3ec;"><thead><tr style="background:#f8fafc;">' + header + '</tr></thead><tbody>' + data.location_matrix_rows + '</tbody></table>');
  }
  if (data.top_location_rows) blocks.push(simpleTable('Top bodega/localidad', data.top_location_rows, ['Bodega/localidad','Total','Dato 1','Observacion'], 'Sin top de localidades.'));
  return blocks.filter(Boolean).join('\n');
}

function buildHtml(item) {
  const data = item.json || {};
  const triggerConfig = getNodeJson('SetTrigger - Flujo');
  const mixedConfig = getNodeJson('SetMixed - Configuracion efectiva');
  const root = data.template_root || mixedConfig.template_root || triggerConfig.template_root || '/opt/n8n-config/templates/mail/v1';
  const key = data.report_template_key || mixedConfig.report_template_key || triggerConfig.report_template_key || 'cmdb-activos-sin-contacto';
  const contract = JSON.parse(readText(path.join(root, 'reports', key + '.json')));
  const partial = (name) => readText(path.join(root, contract.partials[name]));

  const styles = partial('styles');
  const header = render(partial('header'), {
    eyebrow: escapeHtml(contract.header?.eyebrow || 'Automatizacion ITSM / CMDB'),
    title: escapeHtml(data.report_title || data.email_subject || 'Reporte'),
    subtitle: escapeHtml(contract.header?.subtitle || ''),
    itop_organization: escapeHtml(data.itop_organization || '-'),
    generated_at: escapeHtml(data.generated_at || '-'),
    source_label: escapeHtml(data.source_label || data.report_source_label || contract.header?.source_label || '-'),
  });
  const summary = render(partial('summary'), { description: escapeHtml(data.report_description || contract.summary?.description || '') });
  const stats = render(partial('stats'), { stats_rows: statRows(data, contract.stats || []) });
  const criteria = render(partial('criteria'), contract.criteria || {});
  const tables = flagEnabled(data, 'include_detail', true) ? render(partial('tables'), {
    title: contract.tables?.title || 'Detalle operacional',
    subtitle: contract.tables?.subtitle || '',
    content: tableContent(data) || '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="border:1px solid #dbe3ec;"><tr><td style="padding:14px; font-size:13px; color:#64748b;">Sin registros para el criterio del reporte.</td></tr></table>',
  }) : '';
  const notes = flagEnabled(data, 'include_operational_notes', true) ? render(partial('notes'), { notes_list: notesList(data.operational_notes) }) : '';
  const cta = flagEnabled(data, 'include_itop_button_footer', true) ? render(partial('cta'), {
    href: escapeHtml(data.itop_url || '#'),
    label: contract.cta?.label || 'Abrir',
  }) : '';
  const footer = render(partial('footer'), {
    brand: contract.footer?.brand || 'Automatizacion ITSM / CMDB',
    company: escapeHtml(data.company || data.Company || ''),
    generated_at: escapeHtml(data.generated_at || '-'),
  });

  let html = render(partial('layout'), {
    title: escapeHtml(data.report_title || data.email_subject || 'Reporte'),
    styles,
    header,
    summary: flagEnabled(data, 'include_summary', true) ? summary : '',
    stats: flagEnabled(data, 'include_summary', true) ? stats : '',
    criteria,
    tables,
    notes,
    cta,
    footer,
  });
  html = normalizeText(html, false);
  data.email_subject = normalizeText(data.email_subject, true);

  const includeAttachment = flagEnabled(data, 'include_attachment', true);
  const binary = includeAttachment ? (item.binary || {}) : {};
  return {
    json: {
      ...data,
      html,
      template_version: contract.template_version || 'mail-v1',
      template_contract: key,
      include_attachment_effective: includeAttachment,
      attachment_binary_names: includeAttachment && binary.csv ? 'csv' : '',
      has_csv_binary: Boolean(binary.csv),
    },
    binary,
  };
}

return $input.all().map(buildHtml);

function normalizeBoolean(value, fallback = true) {
  if (value === undefined || value === null || value === '') return fallback;
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value !== 0;
  const text = String(value).trim().toLowerCase();
  if (['true', '1', 'yes', 'y', 'si', 's', 'on', 'enabled'].includes(text)) return true;
  if (['false', '0', 'no', 'n', 'off', 'disabled'].includes(text)) return false;
  return fallback;
}

function flag(data, name, fallback = true) {
  return normalizeBoolean(data[name] ?? data.flags?.[name], fallback);
}

return $input.all().flatMap((item) => {
  const data = item.json || {};
  const sendEmail = flag(data, 'send_email', true);
  const sendWhenNoChanges = flag(data, 'send_when_no_changes', true);
  const hayCambios = data.hayCambios === true;

  if (!sendEmail) return [];
  if (!hayCambios && !sendWhenNoChanges) return [];

  const includeAttachment = flag(data, 'include_attachment', true);
  const binary = includeAttachment ? (item.binary || {}) : {};
  const hasCsv = Boolean(binary.csv);

  return [{
    json: {
      ...data,
      attachment_binary_names: includeAttachment && hasCsv ? 'csv' : '',
      include_attachment_effective: includeAttachment,
      has_csv_binary: hasCsv,
      attachment_validation: includeAttachment && hasCsv
        ? 'OK - binario CSV disponible para envio SMTP'
        : (includeAttachment ? 'WARN - include_attachment activo, pero no existe binary.csv' : 'OK - envio sin adjunto por parametro'),
    },
    binary,
  }];
});
